import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    aadhar: "",
    pan: "",
    designation: "",
    department: "",
    salary: "",
    role: "",
    bankName: "",
    accountNumber: "",
    ifsc: "",
    qualification: "",
    university: "",
    passingYear: ""
  });

  /* ================= LOAD EMPLOYEE FOR EDIT ================= */
  useEffect(() => {

    if (!isEditMode) return;

    const loadEmployee = async () => {
      try {
        const token = localStorage.getItem("token");

        const res = await fetch(
          `http://localhost:8080/api/profile/${id}`,
          {
            headers: { Authorization: `Bearer ${token}` }
          }
        );

        if (!res.ok) throw new Error("Failed loading employee");

        const data = await res.json();
        setEmployee(prev => ({ ...prev, ...data }));

      } catch (err) {
        console.error(err);
      }
    };

    loadEmployee();

  }, [id, isEditMode]);


  /* ================= INPUT HANDLER ================= */
  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === "pan") {
      setEmployee({ ...employee, pan: value.toUpperCase() });
      return;
    }

    setEmployee({ ...employee, [name]: value });
  };


  /* ================= SAVE ================= */
  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const token = localStorage.getItem("token");

      const url = isEditMode
        ? `http://localhost:8080/api/profile/${id}`
        : `http://localhost:8080/api/profile`;

      const method = isEditMode ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify(employee)
      });

      if (!res.ok) {
        alert("Save Failed");
        return;
      }

      alert(isEditMode ? "Updated Successfully" : "Employee Created");

      navigate("/admin-dashboard/employee-details");

    } catch (err) {
      console.error(err);
      alert("Server Error");
    }
  };


  /* ================= UI HELPERS ================= */
  const Field = (label, element) => (
    <div className="form-field">
      <label>{label}</label>
      {element}
    </div>
  );


  /* ================= UI ================= */
  return (
    <div className="add-employee-page">

      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      {/* Tabs */}
      <div className="tabs">
        {["personal", "employment", "bank", "education"].map(t => (
          <button
            key={t}
            className={`tab ${activeTab === t ? "active" : ""}`}
            type="button"
            onClick={() => setActiveTab(t)}
          >
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* PERSONAL */}
        {activeTab === "personal" && (
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              {Field("First Name",
                <input name="firstName" value={employee.firstName} onChange={handleChange} />
              )}

              {Field("Last Name",
                <input name="lastName" value={employee.lastName} onChange={handleChange} />
              )}

              {Field("Employee ID",
                <input name="empId" value={employee.empId} onChange={handleChange} />
              )}

              {Field("Gender",
                <input name="gender" value={employee.gender} onChange={handleChange} />
              )}

              {Field("DOB",
                <input type="date" name="dob" value={employee.dob} onChange={handleChange} />
              )}

              {Field("Marital Status",
                <input name="maritalStatus" value={employee.maritalStatus} onChange={handleChange} />
              )}

              {Field("Email",
                <input name="email" value={employee.email} onChange={handleChange} />
              )}

              {Field("Aadhar",
                <input name="aadhar" value={employee.aadhar} onChange={handleChange} />
              )}

              {Field("PAN",
                <input name="pan" value={employee.pan} onChange={handleChange} />
              )}

            </div>
          </>
        )}


        {/* EMPLOYMENT */}
        {activeTab === "employment" && (
          <>
            <h3>Employment Details</h3>
            <div className="employee-grid">

              {Field("Designation",
                <input name="designation" value={employee.designation} onChange={handleChange} />
              )}

              {Field("Department",
                <input name="department" value={employee.department} onChange={handleChange} />
              )}

              {Field("Salary",
                <input name="salary" value={employee.salary} onChange={handleChange} />
              )}

              {Field("Role",
                <input name="role" value={employee.role} onChange={handleChange} />
              )}

            </div>
          </>
        )}


        {/* BANK */}
        {activeTab === "bank" && (
          <>
            <h3>Bank Details</h3>
            <div className="employee-grid">

              {Field("Bank Name",
                <input name="bankName" value={employee.bankName} onChange={handleChange} />
              )}

              {Field("Account Number",
                <input name="accountNumber" value={employee.accountNumber} onChange={handleChange} />
              )}

              {Field("IFSC",
                <input name="ifsc" value={employee.ifsc} onChange={handleChange} />
              )}

            </div>
          </>
        )}


        {/* EDUCATION */}
        {activeTab === "education" && (
          <>
            <h3>Education Details</h3>
            <div className="employee-grid">

              {Field("Qualification",
                <input name="qualification" value={employee.qualification} onChange={handleChange} />
              )}

              {Field("University",
                <input name="university" value={employee.university} onChange={handleChange} />
              )}

              {Field("Passing Year",
                <input name="passingYear" value={employee.passingYear} onChange={handleChange} />
              )}

            </div>
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
